def parse_run_report(text):
    import re

    passed = 0
    total = 0
    integration_pass = False

    func_match = re.search(r'functions implemented:\s*(\d+)\s*/\s*(\d+)', text, re.IGNORECASE)
    if func_match:
        passed = int(func_match.group(1))
        total = int(func_match.group(2))

    if re.search(r'integration:\s*pass', text, re.IGNORECASE):
        integration_pass = True

    return {
        'functions_passed': passed,
        'functions_total': total,
        'integration_pass': integration_pass
    }

