def score_band(pct) -> str:
    # Import needed for type checking
    import numbers

    # Define thresholds as constants
    STRONG_THRESHOLD = 75
    GOOD_THRESHOLD = 50
    PARTIAL_THRESHOLD = 25

    # Treat None or non-numeric as 'weak'
    if pct is None or not isinstance(pct, numbers.Number):
        return 'weak'

    # Check thresholds in descending order
    if pct >= STRONG_THRESHOLD:
        return 'strong'
    elif pct >= GOOD_THRESHOLD:
        return 'good'
    elif pct >= PARTIAL_THRESHOLD:
        return 'partial'
    else:
        return 'weak'

