def minmax_normalize(score_map):
    if not isinstance(score_map, dict) or len(score_map) == 0:
        return {}

    values = list(score_map.values())

    # If fewer than 2 entries, or all values are equal, map to 100.0
    if len(values) < 2:
        return {k: 100.0 for k in score_map}

    min_val = min(values)
    max_val = max(values)

    # If all values are equal
    if min_val == max_val:
        return {k: 100.0 for k in score_map}

    range_val = max_val - min_val
    result = {}
    for k, v in score_map.items():
        normalized = ((v - min_val) / range_val) * 100.0
        result[k] = round(normalized, 2)

    return result

