def weighted_mean(pairs) -> float:
    """
    Compute the weighted mean of an iterable of (value, weight) pairs.

    Returns sum(v*w)/sum(w) rounded to 4 decimal places.
    Returns 0.0 if the total weight is 0 or the input is empty.
    Never raises an exception.
    """
    total_weighted_value = 0.0
    total_weight = 0.0

    try:
        for value, weight in pairs:
            total_weighted_value += value * weight
            total_weight += weight
    except Exception:
        return 0.0

    if total_weight == 0:
        return 0.0

    return round(total_weighted_value / total_weight, 4)

