def jaccard_weighted(a, b, weights=None):
    if weights is None:
        weights = {}

    try:
        set_a = set(a)
        set_b = set(b)

        if not set_a and not set_b:
            return 0.0

        common = set_a & set_b
        union = set_a | set_b

        get_weight = lambda x: weights.get(x, 1.0)

        sum_common = sum(get_weight(x) for x in common)
        sum_union = sum(get_weight(x) for x in union)

        if sum_union == 0:
            return 0.0

        result = sum_common / sum_union
        return round(result, 4)
    except Exception:
        return 0.0

