def zscore(values):
    import math

    if not values:
        return []

    n = len(values)
    if n < 2:
        return [0.0] * n

    mean = sum(values) / n
    variance = sum((x - mean) ** 2 for x in values) / n
    stdev = math.sqrt(variance)

    if stdev == 0:
        return [0.0] * n

    return [round((x - mean) / stdev, 4) for x in values]

