def pick_best(items, key):
    """Return the item with the highest key(item) value.

    Ties are broken by first occurrence. If items is empty or key(item) is
    None/empty for all items, return None. Never raises an exception.
    """
    best_item = None
    best_value = None
    has_been_set = False

    for item in items:
        try:
            k = key(item)
        except Exception:
            continue

        # Check if the key value is None or "empty"
        if k is None:
            continue

        # Check for empty values (empty strings, empty lists, etc.)
        if isinstance(k, (str, bytes, list, tuple, dict, set, frozenset)):
            if len(k) == 0:
                continue

        # For numeric-like comparisons, we need to handle the first valid value
        if not has_been_set:
            best_item = item
            best_value = k
            has_been_set = True
        else:
            try:
                if k > best_value:
                    best_item = item
                    best_value = k
            except TypeError:
                # Can't compare, skip
                continue

    return best_item

