def aggregate_to_percent(weighted_scores: dict[str, float], weights: dict[str, float] | None = None) -> float:
    if not weighted_scores:
        return 0.0

    if weights is None:
        weights = {}

    numerator = sum(score * weights.get(k, 1.0) for k, score in weighted_scores.items())
    denominator = sum(weights.get(k, 1.0) for k in weighted_scores)

    if denominator == 0:
        return 0.0

    result = (numerator / denominator) * 100.0
    return max(0.0, min(100.0, result))

