def explain_score_breakdown(category_scores: dict[str, float], weights: dict[str, float] | None = None, total_percent: float | None = None) -> str:
    if weights is None:
        weights = {k: 1.0 for k in category_scores}

    contributions = []
    for cat, score in category_scores.items():
        w = weights.get(cat, 1.0)
        contrib = score * w
        contributions.append((cat, score, w, contrib))

    contributions.sort(key=lambda x: x[3], reverse=True)

    lines = []
    for cat, score, w, contrib in contributions:
        lines.append(f"{cat}: {score:.0%} (weight {w:.1f})")

    if total_percent is None:
        total_weight = sum(weights.get(c, 1.0) for c in category_scores)
        if total_weight == 0:
            overall = 0.0
        else:
            overall = sum(score * weights.get(c, 1.0) for c, score, w, contrib in contributions) / total_weight
        total_percent = max(0.0, min(100.0, overall * 100))

    lines.append(f"Overall: {total_percent:.1f}/100")
    return "\n".join(lines)

