    functions = spec.get('functions', [])

    # Add 25 if spec['functions'] is non-empty
    if functions:
        score += 25

    # Add 25 if the average number of items in each function's 'tests' list is >= 4
    if functions:
        total_tests = sum(len(f.get('tests', [])) for f in functions)
        avg_tests = total_tests / len(functions)
        if avg_tests >= 4:
            score += 25
    else:
        # treat average as 0 if functions is empty, so condition not met
        pass

    # Add 25 if 1 <= len(spec['functions']) <= 5
    if 1 <= len(functions) <= 5:
        score += 25

    # Add 25 if spec['prompt_length'] >= 100
