def parse_metrics_line(line: str) -> dict:
    """
    Parse a metrics line of the form:
    metric_name:value or metric_name:value unit

    Returns a dictionary with the metric name as key and value/unit as needed.
    """
    line = line.strip()
    if not line:
        return {}

    parts = line.split()

    if len(parts) < 2:
        return {}

    key_value = parts[0]

    if ':' not in key_value:
        return {}

    name, value_str = key_value.split(':', 1)

    try:
        value = float(value_str)
        # Try to convert to int if it's a whole number
        if value == int(value):
            value = int(value)
    except ValueError:
        return {}

    result = {name: value}

    # If there are additional parts, treat them as units
    if len(parts) > 2:
        unit = ' '.join(parts[1:])
        # Store unit in a special way - append to value or add separate key
        result[f'{name}_unit'] = unit

    return result

