    if status in ("pass", "PASS", "passed", "PASS/FAILED", "PASS"):
        return "PASS"
    elif status in ("fail", "FAIL", "failed", "FAILED", "failure"):
        return "FAIL"
    elif status in ("skip", "SKIP", "skipped", "aborted", "ABORTED"):
        return "SKIP"

    # Fallback: check for common patterns
    if "fail" in status.lower() or "failure" in status.lower():
        return "FAIL"
    elif "skip" in status.lower():
        return "SKIP"
    else:
        return "PASS"

