def detect_consistent_failures(records: list) -> list:
    """
    Detect function names that always fail (passed=False) across all occurrences.

    Args:
        records: List of dicts with 'function' (str) and 'passed' (bool) keys

    Returns:
        Sorted list of function names that are consistently False in 'passed'
    """
    # Track function statuses
    function_statuses = {}

    for record in records:
        func_name = record['function']
        passed = record['passed']

        if func_name not in function_statuses:
            function_statuses[func_name] = []
        function_statuses[func_name].append(passed)

    # Find functions that always failed
    consistently_failed = []
    for func_name, statuses in function_statuses.items():
        if all(not passed for passed in statuses):
            consistently_failed.append(func_name)

    # Return sorted list
    return sorted(consistently_failed)

