def estimate_cycles_to_completion(current: float, target: float, rate: float) -> int:
    import math

    # If already at or above target, no cycles needed
    if current >= target:
        return 0

    # If rate is non-positive, cannot converge
    if rate <= 0:
        return 99

    # Calculate cycles needed
    cycles = math.ceil((target - current) / rate)

    # Clamp to [1, 99]
    return max(1, min(99, cycles))

