def score_spec_quality(spec: dict) -> float:
    """
    Score the quality of a specification dictionary based on how many functions are tested.

    Args:
        spec: Dictionary with spec information, expected to have 'functions' and 'tested' keys

    Returns:
        1.0 if all functions are tested, otherwise the ratio of tested functions
    """
    if not spec:
        return 0.0

    # Get the list of all functions in the spec
    functions = spec.get('functions', [])

    # If no functions defined, return 0.0
    if not functions:
        return 0.0

    # Get the set of tested function names
    tested = set()

    # Check various possible structures for test information
    tests = spec.get('tests', [])

    if isinstance(tests, list):
        for test in tests:
            if isinstance(test, dict):
                test_func = test.get('function', test.get('function_name', test.get('name', '')))
                if test_func:
                    tested.add(test_func)
            elif isinstance(test, str):
                tested.add(test)
    elif isinstance(tests, dict):
        tested = set(tests.keys())
    elif isinstance(tests, set):
        tested = tests

    # Also check 'tested_functions' key if present
    tested_functions = spec.get('tested_functions', spec.get('tested', []))
    if isinstance(tested_functions, list):
        for tf in tested_functions:
            if isinstance(tf, dict):
                func_name = tf.get('function', tf.get('function_name', tf.get('name', '')))
                if func_name:
                    tested.add(func_name)
            elif isinstance(tf, str):
                tested.add(tf)

    # Get all function names
    func_names = set()
    if isinstance(functions, list):
        for f in functions:
            if isinstance(f, dict):
                func_name = f.get('name', f.get('function_name', f.get('function', '')))
                if func_name:
                    func_names.add(func_name)
            elif isinstance(f, str):
                func_names.add(f)
    elif isinstance(functions, dict):
        func_names = set(functions.keys())
    elif isinstance(functions, set):
        func_names = functions

    if not func_names:
        return 0.0

    # Calculate the score
    num_tested = len(tested & func_names)
    score = num_tested / len(func_names)

    # Return 1.0 if all functions are tested
    if score >= 1.0:
        return 1.0

    return float(score)

