def format_build_status(report: dict) -> str:
    """
    Returns 'PASS', 'FAIL', or 'SKIP' based on the build status report.

    Args:
        report: A dictionary containing build status information.

    Returns:
        A string representing the build status: 'PASS', 'FAIL', or 'SKIP'.
    """
    # Check for various possible keys that might indicate build status
    status_keys = ['status', 'build_status', 'result', 'outcome']

    for key in status_keys:
        if key in report:
            value = report[key]
            if isinstance(value, str):
                if value.lower() in ['pass', 'passed', 'success', 'successful']:
                    return 'PASS'
                elif value.lower() in ['fail', 'failed', 'failure', 'error']:
                    return 'FAIL'
                elif value.lower() in ['skip', 'skipped', 'not_run', 'not run']:
                    return 'SKIP'
            elif isinstance(value, bool):
                if value:
                    return 'PASS'
                else:
                    return 'FAIL'
            elif isinstance(value, (int, float)):
                if value == 0 or value == 1:
                    return 'PASS' if value == 1 else 'FAIL'

    # Check for error/failure indicators
    error_keys = ['error', 'errors', 'failure', 'failures', 'exception']
    for key in error_keys:
        if key in report:
            value = report[key]
            if value:
                return 'FAIL'

    # Check for success indicators
    success_keys = ['success', 'successful', 'passed', 'pass']
    for key in success_keys:
        if key in report:
            value = report[key]
            if value:
                return 'PASS'

    return 'FAIL'

