        for ext in ('.pyc', '.pyo', '.log', '.tmp', '.orig', '.bak', '.db-journal', '.rej'):
            if basename_lower.endswith(ext):
                return True
        if basename_lower == 'run_report.md':
            return True
        return False
    except Exception:
        return False

