def resolve_refs(refs, fn_tests):
    try:
        if not refs or not fn_tests:
            return []
        out = []
        seen = set()

        def add(fn, test):
            key = (fn, test)
            if key not in seen:
                seen.add(key)
                out.append([fn, test])

        for ref in refs:
            try:
                if not isinstance(ref, str):
                    continue
                if ref in fn_tests:
                    tests = fn_tests[ref]
                    if tests:
                        for t in tests:
                            add(ref, t)
                    continue
                if ':' not in ref:
                    continue
                fn, idx_s = ref.rsplit(':', 1)
                if fn not in fn_tests:
                    continue
                if not idx_s.isdigit():
                    continue
                idx = int(idx_s)
                tests = fn_tests[fn]
                if tests is None or idx >= len(tests):
                    continue
                add(fn, tests[idx])
            except Exception:
                continue
        return out
    except Exception:
        return []

